function buildEngagementGamePool(includeTtt){const done=engagementBootstrap?.cards_done_today||[];const pool=[];const pick=(arr)=>arr[Math.floor(Math.random()*arr.length)];const ids=allSuggestions.filter((s)=>!swipeConsumedIds.has(s.id)).map((s)=>s.id);const guessEl=(engagementBootstrap?.guess_eligible_ids||[]).filter((id)=>!swipeConsumedIds.has(id));const dlm=engagementBootstrap?.dilemma;if(!done.includes("importance")&&ids.length)pool.push({kind:"special",type:"importance",refId:pick(ids)});if(!done.includes("activity"))pool.push({kind:"special",type:"activity"});if(!done.includes("guess")&&guessEl.length)pool.push({kind:"special",type:"guess",refId:pick(guessEl)});if(!done.includes("message"))pool.push({kind:"special",type:"message"});if(!done.includes("mood"))pool.push({kind:"special",type:"mood"});if(!done.includes("dilemma")&&dlm&&dlm.id)pool.push({kind:"special",type:"dilemma"});if(includeTtt&&!done.includes("ttt"))pool.push({kind:"special",type:"ttt"});const mps=engagementBootstrap?.music_polls||[];for(const poll of mps){const ct=`music_${poll.id}`;if(!done.includes(ct)){pool.push({kind:"special",type:"music_poll",poll});}}
return pool;}
function buildSwipeDeck(){if(!isTouchDevice())return;const seen=new Set();const sugItems=[];for(const s of allSuggestions){if(swipeConsumedIds.has(s.id))continue;if(!seen.has(s.id)){seen.add(s.id);sugItems.push({kind:"suggestion",id:s.id});}}
const shuffledSug=shuffle(sugItems);const gamePool=buildEngagementGamePool(true);const shuffledGames=shuffle(gamePool);let deck;if(shuffledSug.length>0){deck=[...shuffledSug,...shuffledGames];}else if(shuffledGames.length>0){deck=[...shuffledGames];}else{deck=[{kind:"special",type:"ttt",emptyState:true}];}
swipeDeckItems=deck;clampSwipeIndex();}
