async function engagementPingPresence(){try{await API.post("/api/engagement/ping",{type:"presence"});}catch(e){}}
function clampSwipeIndex(){if(swipeDeckItems.length===0){swipeIndex=0;return;}
if(swipeIndex>=swipeDeckItems.length)swipeIndex=swipeDeckItems.length-1;if(swipeIndex<0)swipeIndex=0;}
const TTT_LINES=[[0,1,2],[3,4,5],[6,7,8],[0,3,6],[1,4,7],[2,5,8],[0,4,8],[2,4,6],];function tttWinner(cells){for(const[a,b,c]of TTT_LINES){if(cells[a]&&cells[a]===cells[b]&&cells[a]===cells[c])return cells[a];}
return cells.every(Boolean)?"draw":null;}
function tttEmptyIndices(cells){const r=[];for(let i=0;i<9;i++)if(!cells[i])r.push(i);return r;}
function tttMinimax(cells,maxTurn){const w=tttWinner(cells);if(w==="O")return 1;if(w==="X")return-1;if(w==="draw")return 0;const moves=tttEmptyIndices(cells);if(maxTurn){let best=-2;for(const m of moves){const next=[...cells];next[m]="O";best=Math.max(best,tttMinimax(next,false));}
return best;}
let best=2;for(const m of moves){const next=[...cells];next[m]="X";best=Math.min(best,tttMinimax(next,true));}
return best;}
function tttBestMoveO(cells){let bestScore=-2;let bestM=-1;for(const m of tttEmptyIndices(cells)){const next=[...cells];next[m]="O";const sc=tttMinimax(next,false);if(sc>bestScore){bestScore=sc;bestM=m;}}
return bestM;}
function tttRedrawGrid(){const cells=document.querySelectorAll(".ttt-cell");if(!cells.length||!tttBoard)return;cells.forEach((el,i)=>{el.textContent=tttBoard[i]||"";});}
function tttFinish(msg){tttGameOver=true;const st=document.getElementById("swipe-ttt-status");if(st)st.textContent=msg;const btn=document.getElementById("swipe-ttt-done");if(btn)btn.classList.remove("hidden");}
function handleTttCellClick(idx){const item=swipeDeckItems[swipeIndex];if(!item||item.kind!=="special"||item.type!=="ttt")return;if(tttGameOver||!tttBoard)return;if(tttBoard[idx])return;tttBoard[idx]="X";tttRedrawGrid();const w=tttWinner(tttBoard);if(w==="X")return tttFinish("Tu as gagné !");if(w==="draw")return tttFinish("Match nul.");const ai=tttBestMoveO(tttBoard);if(ai>=0)tttBoard[ai]="O";tttRedrawGrid();const w2=tttWinner(tttBoard);if(w2==="O")tttFinish("L’IA gagne.");else if(w2==="draw")tttFinish("Match nul.");}
