if(swipeIndex>=list.length-1){const cur=list[swipeIndex];if(cur&&cur.kind==="suggestion"){swipeConsumedIds.add(cur.id);saveSwipeConsumedIds();showFeedback("Plus de nouvelles suggestions.","info");buildSwipeDeck();lastSwipeDeckSig=computeSwipeDeckSig();clampSwipeIndex();swipeIndex=0;renderSwipeView();return;}
showFeedback("Plus de nouvelles suggestions.","info");return;}
const cur=list[swipeIndex];if(cur&&cur.kind==="suggestion"){swipeConsumedIds.add(cur.id);saveSwipeConsumedIds();}
