async function handleEngagementClick(ev){const t=ev.target.closest("[data-eng]");if(!t)return;const eng=t.dataset.eng;if(eng==="ttt-replay"){ev.preventDefault();initTttUi();return;}
if(eng==="swipe-empty-retry"){ev.preventDefault();await loadSuggestions({reason:"user"});lastSwipeDeckSig=computeSwipeDeckSig();buildSwipeDeck();clampSwipeIndex();renderSwipeView();return;}
if(eng==="imp"){const sid=parseInt(t.dataset.sid,10);const level=parseInt(t.dataset.level,10);const{data,status}=await API.post("/api/engagement/importance",{suggestion_id:sid,level});if(status===200&&data.ok){const s=allSuggestions.find((x)=>x.id===sid);if(s){s.importance_score=data.importance_score;s.hot=(data.importance_score||0)>=70;}
await refreshEngagementBootstrap();swipeGoNext();}else showFeedback((data&&data.error)||"Erreur","error");return;}
if(eng==="act-dismiss"){await API.post("/api/engagement/activity-card-dismiss",{});await refreshEngagementBootstrap();swipeGoNext();return;}
if(eng==="music-poll-dismiss"){swipeGoNext();return;}
if(eng==="guess"){const sid=parseInt(t.dataset.sid,10);const bucket=t.dataset.bucket;const{data,status}=await API.post("/api/engagement/guess",{suggestion_id:sid,bucket});if(status===200){swipeGuessReveal[sid]={actual_pct:data.actual_pct,correct:data.correct,};renderSwipeView();}else showFeedback((data&&data.error)||"Erreur","error");return;}
if(eng==="guess-next"){swipeGoNext();return;}
if(eng==="msg-send"){const pseudo=(document.getElementById("swipe-eng-pseudo")?.value||"").trim();const msg=(document.getElementById("swipe-eng-msg")?.value||"").trim();const{data,status}=await API.post("/api/engagement/message",{display_name:pseudo,message:msg,});if(status===200&&data.ok){await refreshEngagementBootstrap();swipeGoNext();}else showFeedback((data&&data.error)||"Erreur","error");return;}
if(eng==="mood"){const mood=t.dataset.mood;const{data,status}=await API.post("/api/engagement/mood",{mood});if(status===200&&data.ok){await refreshEngagementBootstrap();swipeGoNext();}else showFeedback((data&&data.error)||"Erreur","error");return;}
if(eng==="dilemma-vote"){const did=parseInt(t.dataset.did,10);const side=(t.dataset.side||"").toLowerCase();const{data,status}=await API.post("/api/engagement/dilemma-vote",{dilemma_id:did,side});if(status===200){engagementBootstrap=engagementBootstrap||{};engagementBootstrap.dilemma=data;renderSwipeView();}else if(status===409){await refreshEngagementBootstrap();renderSwipeView();}else showFeedback((data&&data.error)||"Erreur","error");return;}
if(eng==="dilemma-skip"){const{data,status}=await API.post("/api/engagement/dilemma-skip",{});if(status===200){await refreshEngagementBootstrap();buildSwipeDeck();clampSwipeIndex();renderSwipeView();}else showFeedback((data&&data.error)||"Erreur","error");return;}
if(eng==="dilemma-next"){swipeGoNext();return;}
if(eng==="ttt-dismiss"){const{data,status}=await API.post("/api/engagement/ttt-dismiss",{});if(status===200){await refreshEngagementBootstrap();buildSwipeDeck();clampSwipeIndex();renderSwipeView();}else showFeedback((data&&data.error)||"Erreur","error");return;}}
