function showFeedback(message,type){feedback.textContent=message;feedback.className=`feedback ${type} feedback-enter`;feedback.classList.remove("hidden");requestAnimationFrame(()=>feedback.classList.remove("feedback-enter"));setTimeout(()=>{feedback.classList.add("feedback-exit");setTimeout(()=>{feedback.classList.add("hidden");feedback.classList.remove("feedback-exit");},300);},4000);}
function hideFeedback(){feedback.classList.add("hidden");}
function setLoading(loading){submitBtn.disabled=loading;submitBtn.querySelector(".btn-text").classList.toggle("hidden",loading);submitBtn.querySelector(".btn-loader").classList.toggle("hidden",!loading);}
function clearInput(){input.value="";charCount.textContent="0 / 500";submitBtn.disabled=true;}
